// Simulação de busca no NAS (substituir por integração real)
const query = $input.item.json.query || '';

// Simular busca de arquivos
const arquivos = [
  {
    nome: 'Certificado_INMETRO_2024.pdf',
    caminho: '/nas/certificados/inmetro/Certificado_INMETRO_2024.pdf',
    tipo: 'PDF',
    tamanho: '2.5 MB',
    dataModificacao: '2024-01-15',
    categoria: 'certificado',
    permissoes: 'publico',
    cliente: null,
    fornecedor: null,
    op: null
  },
  {
    nome: 'Proposta_Cliente_ABC_2024.pdf',
    caminho: '/nas/propostas/clientes/Proposta_Cliente_ABC_2024.pdf',
    tipo: 'PDF',
    tamanho: '1.8 MB',
    dataModificacao: '2024-02-20',
    categoria: 'proposta',
    permissoes: 'restrito',
    cliente: 'ABC Ltda',
    fornecedor: null,
    op: 'OP-2024-001'
  },
  {
    nome: 'Manual_Operacao_Equipamento_X.pdf',
    caminho: '/nas/manuais/equipamentos/Manual_Operacao_Equipamento_X.pdf',
    tipo: 'PDF',
    tamanho: '5.2 MB',
    dataModificacao: '2023-11-10',
    categoria: 'manual',
    permissoes: 'publico',
    cliente: null,
    fornecedor: 'Fornecedor XYZ',
    op: null
  },
  {
    nome: 'Norma_ISO_9001_2015.pdf',
    caminho: '/nas/normas/iso/Norma_ISO_9001_2015.pdf',
    tipo: 'PDF',
    tamanho: '3.1 MB',
    dataModificacao: '2023-08-05',
    categoria: 'norma',
    permissoes: 'publico',
    cliente: null,
    fornecedor: null,
    op: null
  }
];

// Filtrar arquivos baseado na query
const resultados = arquivos.filter(arq => {
  const searchText = query.toLowerCase();
  return arq.nome.toLowerCase().includes(searchText) ||
         arq.categoria.toLowerCase().includes(searchText) ||
         (arq.cliente && arq.cliente.toLowerCase().includes(searchText)) ||
         (arq.fornecedor && arq.fornecedor.toLowerCase().includes(searchText)) ||
         (arq.op && arq.op.toLowerCase().includes(searchText));
});

if (resultados.length === 0) {
  return 'Nenhum arquivo encontrado para: ' + query;
}

// Formatar resultados
let resposta = 'Arquivos encontrados (' + resultados.length + '):\n\n';
resultados.forEach((arq, idx) => {
  resposta += (idx + 1) + '. ' + arq.nome + '\n';
  resposta += '   Caminho: ' + arq.caminho + '\n';
  resposta += '   Tipo: ' + arq.tipo + ' | Tamanho: ' + arq.tamanho + '\n';
  resposta += '   Categoria: ' + arq.categoria + '\n';
  resposta += '   Permissões: ' + arq.permissoes + '\n';
  if (arq.cliente) resposta += '   Cliente: ' + arq.cliente + '\n';
  if (arq.fornecedor) resposta += '   Fornecedor: ' + arq.fornecedor + '\n';
  if (arq.op) resposta += '   OP: ' + arq.op + '\n';
  resposta += '   Modificado: ' + arq.dataModificacao + '\n\n';
});

return resposta;

// Validação de permissões (substituir por sistema real de permissões)
const arquivo = $input.item.json.arquivo || '';
const usuario = $input.item.json.usuario || 'anonimo';

// Simular verificação de permissões
const permissoes = {
  'Certificado_INMETRO_2024.pdf': 'publico',
  'Proposta_Cliente_ABC_2024.pdf': 'restrito',
  'Manual_Operacao_Equipamento_X.pdf': 'publico',
  'Norma_ISO_9001_2015.pdf': 'publico'
};

const usuariosAutorizados = {
  'Proposta_Cliente_ABC_2024.pdf': ['admin', 'vendas', 'gerencia']
};

const permissao = permissoes[arquivo] || 'desconhecido';

if (permissao === 'publico') {
  return 'ACESSO PERMITIDO: Arquivo público, sem restrições.';
}

if (permissao === 'restrito') {
  const autorizados = usuariosAutorizados[arquivo] || [];
  if (autorizados.includes(usuario)) {
    return 'ACESSO PERMITIDO: Usuário autorizado para arquivo restrito.';
  } else {
    return 'ACESSO NEGADO: Arquivo restrito. Usuário não autorizado. Solicite permissão ao administrador.';
  }
}

if (permissao === 'confidencial') {
  return 'ACESSO NEGADO: Arquivo confidencial. Acesso apenas para administradores.';
}

return 'ACESSO NEGADO: Permissões desconhecidas para este arquivo.';

